{
  "title": "3-month leaner + fitter build",
  "dates": "01 Feb 2026 → 01 May 2026",
  "overview": "3-phase plan: (1) build a base without frying you, (2) push the engine (VO₂) while keeping muscle, (3) sharpen the blade and introduce outdoors once Munich warms up. You’re already consistent with lifting + HIIT + Zwift, so the plan keeps 5 purposeful workouts/week (less random hard, more strategic hard).",
  "assumptions": {
    "session_length": "Most workouts are 45–70 min.",
    "winter_constraint": "Feb + most of Mar stay indoors (gym, Zwift, treadmill). Outdoor running/cycling is introduced in April as temperatures improve in Munich.",
    "strength_approach": "No supersets. Strength sessions use straight sets with adequate rest."
  },
  "phases": [
    {
      "name": "Phase 1 (🧱 Foundation & Ramp)",
      "dates": "01 Feb → 28 Feb",
      "objective": "Build a reliable weekly rhythm, boost aerobic base (for fat-loss support + VO₂ later), and maintain strength while you start leaning out.",
      "weekly_structure": {
        "sessions_per_week": 5,
        "items": [
          "2× Strength (Gym, full-body or upper/lower) — straight sets, controlled tempo",
          "1× Zwift intervals (short/medium) — structured, not maximal",
          "1× Zone 2 aerobic (Zwift or treadmill easy) — steady “can talk” pace",
          "1× HIIT (Friday evening) — social suffer-fest"
        ],
        "optional_add_ons": "Optional add-ons that don’t count as workouts: 15–25 min easy spin or a short yoga/mobility flow on 1–2 rest days."
      },
      "progression_focus": [
        "Add a little volume (1–2 total sets/week across key lifts) or small load increases while keeping form pristine.",
        "Gradually extend Zone 2 duration (e.g., +5–10 min/week).",
        "Keep HIIT intense but repeatable (finish feeling like you could do 1 more round)."
      ],
      "risk_to_manage": [
        "Stacking intensity (HIIT + hard Zwift + heavy legs) → fatigue spiral.",
        "Winter + indoor training monotony → going too hard for entertainment."
      ],
      "success_signals": [
        "Hitting 5 sessions/week with stable energy and no joint grumbles.",
        "Zwift workouts feel more controlled at the same effort.",
        "Waist trend starts moving without being “flatlined tired” by Thursday."
      ]
    },
    {
      "name": "Phase 2 (🔥 Build & Intensify)",
      "dates": "01 Mar → 04 Apr",
      "objective": "Turn up conditioning to drive VO₂ up and help body comp, while using minimal-effective-dose strength to keep muscle/shape.",
      "weekly_structure": {
        "sessions_per_week": 5,
        "items": [
          "2× Strength (Gym) — slightly lower total volume than Phase 1, heavier “keep the signal” work",
          "2× Bike quality (Zwift): 1× VO₂/threshold-focused + 1× longer aerobic (Zone 2 / tempo blend depending on fatigue)",
          "1× HIIT Friday — keep it, manage the rest of the week around it"
        ],
        "optional_add_ons": "If you like doubles: occasional AM easy 20 min spin + PM strength on one day—only when recovery feels solid."
      },
      "progression_focus": [
        "Progress bike intensity by increasing total time near threshold/VO₂ (often more work rather than harder every session).",
        "Strength: maintain key lifts with low-to-moderate volume; avoid chasing pump/size."
      ],
      "risk_to_manage": [
        "Overuse / CNS fatigue from too many redline days (HIIT + VO₂ + heavy legs).",
        "Sleep/restore mismatch (WFH flexibility making training feel available 24/7)."
      ],
      "success_signals": [
        "VO₂/threshold sessions become more repeatable (less “death-by-interval-3”).",
        "Strength numbers stay mostly stable (or slightly down) but you feel athletic.",
        "Visible leanness changes: sharper midsection outline, better vascularity during sessions."
      ]
    },
    {
      "name": "Phase 3 (✨ Sharpen, Lean-Out & Spring Transition)",
      "dates": "05 Apr → 01 May",
      "objective": "Hold strength, keep VO₂ climbing, tighten the look while reducing fatigue, and introduce outdoor sessions (weather-permitting) for freshness and easy calorie burn without extra brutality.",
      "weekly_structure": {
        "sessions_per_week": 5,
        "items": [
          "2× Strength (Gym) — crisp, efficient, leave 1–2 reps in the tank",
          "1× HIIT Friday — keep it fun; don’t turn it into a weekly near-death ritual",
          "1× Quality endurance — Zwift threshold or treadmill progression run",
          "1× Outdoor aerobic (preferred) OR indoor fallback: outdoor run/ride (easy/moderate) if conditions are decent; otherwise Zwift Zone 2 / treadmill easy"
        ]
      },
      "progression_focus": [
        "Shift from “more work” to “better work”: maintain intensity but trim junk volume.",
        "Add outdoor duration gradually (fresh legs + spring motivation makes it easy to overdo)."
      ],
      "risk_to_manage": [
        "Spring ego: first sunny day = accidental 2.5h hammerfest.",
        "Letting strength drop too far (still want athletic + defined, not cardio-only skinny)."
      ],
      "success_signals": [
        "Visibly tighter week to week (waist down, abs showing more consistently).",
        "VO₂ markers up: hard sessions feel smoother; recovery between efforts improves.",
        "Finish the program feeling sharp, not cooked."
      ]
    }
  ],
  "closing": "If you follow the arc build → intensify → sharpen, you’ll be set up to chase the ~11% look with a real shot at visible abs + VO₂ up by May, without turning every session into a motivational crisis after work. Use mornings/afternoons, keep Friday HIIT sacred, and keep winter indoors until Munich behaves."
}

parameters.jsCode:
const activities = $input.all().map((item) => item.json);

const cleanedData = activities.map((activity) => ({
  sport_type: activity.sport_type,
  duration: Math.floor(activity.moving_time / 60),
  date: activity.start_date,
  suffer_score: activity.suffer_score,
  load: activity.kilojoules,
}));

return [{ json: { stravaActivities: cleanedData } }];
